// Preprocess: validate, normalize, split into speaker-labeled sentences
const body = $input.first().json.body;
const rawText = typeof body === 'object' && body !== null ? body.text : body;

if (!rawText || typeof rawText !== 'string') {
  throw new Error('No text field in request body.');
}

const SPEAKER_RE = /^\s*([A-Za-z][\w .'\-]{0,30}?)\s*[:\-]\s*(.*)$/;

function splitSentences(text) {
  return text.split(/(?<=[.!?])\s+(?=[A-Z0-9"'])/).map(s => s.trim()).filter(Boolean);
}

const lines = rawText.replace(/\r\n/g, '\n').split('\n').map(l => l.trim()).filter(Boolean);
const sentences = [];
let idx = 0;

for (const line of lines) {
  const m = line.match(SPEAKER_RE);
  const speaker = m ? m[1].trim() : null;
  const body = m ? m[2] : line;
  for (const s of splitSentences(body)) {
    sentences.push({ index: idx++, speaker, text: s });
  }
}

if (sentences.length === 0) throw new Error('No analyzable sentences found.');

const table = sentences.map(s => `${s.index}\t${s.speaker ?? 'Unknown'}\t${s.text}`).join('\n');

return [{ json: { sentences, table, raw: rawText } }];

// Aggregate: merge LLM output with pre-segmented sentences
const raw = $('OpenAI').first().json;
const llmRaw = raw.message?.content ?? raw.content ?? raw.text ?? '{}';
const sentences = $('Preprocess').first().json.sentences;

let parsed;
try { parsed = JSON.parse(typeof llmRaw === 'string' ? llmRaw : JSON.stringify(llmRaw)); }
catch { parsed = typeof llmRaw === 'object' ? llmRaw : {}; }

const EMOTIONS = ['joy','satisfaction','anger','frustration','sadness','fear','neutral','surprise','disgust','anticipation'];
const SENTIMENTS = ['Positive','Negative','Neutral'];

function clamp(n, lo, hi) { return Math.max(lo, Math.min(hi, isFinite(n) ? n : 0)); }
function clampScore(n) { return clamp(n, -1, 1); }
function toSentiment(score) {
  if (score > 0.15) return 'Positive';
  if (score < -0.15) return 'Negative';
  return 'Neutral';
}
function avg(arr) { return arr.length ? arr.reduce((a,b)=>a+b,0)/arr.length : 0; }
function oneOf(v, opts, fb) { return opts.includes(v) ? v : fb; }
function normScale(v, fb, lo, hi) {
  if (typeof v !== 'number' || !isFinite(v)) return fb;
  const n = v <= 10 ? v * 10 : v;
  return Math.round(clamp(n, lo, hi));
}

// Merge sentence-level analysis
const byIndex = new Map();
for (const s of (parsed.sentences ?? [])) {
  byIndex.set(s.index, { sentiment: s.sentiment, score: s.score, emotion: s.emotion });
}
const merged = sentences.map(s => {
  const a = byIndex.get(s.index);
  return {
    index: s.index,
    speaker: s.speaker,
    text: s.text,
    sentiment: oneOf(a?.sentiment, SENTIMENTS, 'Neutral'),
    score: clampScore(a?.score ?? 0),
    emotion: EMOTIONS.includes(a?.emotion) ? a.emotion : 'neutral'
  };
});

// Normalize emotion distribution (10 emotions)
const emoBase = Object.fromEntries(EMOTIONS.map(e=>[e,0]));
if (parsed.emotions && typeof parsed.emotions === 'object') {
  for (const e of EMOTIONS) if (typeof parsed.emotions[e] === 'number') emoBase[e] = parsed.emotions[e];
}
const emoTotal = Object.values(emoBase).reduce((a,b)=>a+b,0) || 1;
for (const e of EMOTIONS) emoBase[e] = +(emoBase[e]/emoTotal).toFixed(3);

// KPI derivation fallbacks
const scores = merged.map(s=>s.score);
const n = scores.length;
const t1 = Math.floor(n/3), t2 = Math.floor(2*n/3);
const half = Math.ceil(n/2);
const firstHalf = avg(scores.slice(0,half));
const secondHalf = avg(scores.slice(half));
const delta = secondHalf - firstHalf;
const overallScore = clampScore(parsed.overall?.score ?? avg(scores));

const customerSentences = merged.filter(s=>s.speaker?.toLowerCase()==='customer');
const src = customerSentences.length ? customerSentences : merged;
const total = src.length || 1;
const promoters = src.filter(s=>s.score>0.5).length;
const detractors = src.filter(s=>s.score<-0.3).length;
const derivedNps = Math.round(clamp((promoters-detractors)/total*100,-100,100));

const minScore = scores.length ? Math.min(...scores) : 0;
const derivedIntensity = Math.round(Math.abs(minScore)*100);
const substantive = merged.filter(s=>s.text.split(' ').length>4).length;
const derivedSilence = Math.round(substantive/Math.max(1,n)*100);

let alterCount = 0;
for (let i=1; i<merged.length; i++) if (merged[i].speaker !== merged[i-1].speaker) alterCount++;
const alterRate = alterCount / Math.max(1, n-1);
const derivedInterrupt = alterRate > 0.8 && overallScore < -0.1 ? 'high' : alterRate > 0.6 ? 'medium' : 'low';

// Talk/listen ratio (computed here, not from LLM)
const counts = {agent:0, customer:0, unknown:0};
for (const s of merged) {
  const k = s.speaker?.toLowerCase();
  if (k==='agent') counts.agent++;
  else if (k==='customer') counts.customer++;
  else counts.unknown++;
}
const talkRatio = {
  agent: Math.round(counts.agent/n*100),
  customer: Math.round(counts.customer/n*100),
  unknown: Math.round(counts.unknown/n*100)
};

// Call phase sentiment
const phaseAvg = (slice) => toSentiment(avg(slice.map(s=>s.score)));
const callPhase = {
  opening: oneOf(parsed.kpis?.call_phase_sentiment?.opening, SENTIMENTS, phaseAvg(merged.slice(0,t1))),
  middle: oneOf(parsed.kpis?.call_phase_sentiment?.middle, SENTIMENTS, phaseAvg(merged.slice(t1,t2))),
  closing: oneOf(parsed.kpis?.call_phase_sentiment?.closing, SENTIMENTS, phaseAvg(merged.slice(t2)))
};

const kpis = parsed.kpis ?? {};
const RISK = ['low','medium','high'];
const TREND = ['improving','declining','flat'];
const RES = ['resolved','partial','unresolved'];

const result = {
  overall: {
    sentiment: oneOf(parsed.overall?.sentiment, SENTIMENTS, toSentiment(overallScore)),
    score: overallScore,
    confidence: clamp(parsed.overall?.confidence ?? 0.8, 0, 1),
    reasoning: parsed.overall?.reasoning ?? ''
  },
  sentences: merged,
  emotions: emoBase,
  summary: parsed.summary ?? '',
  kpis: {
    csat_proxy: normScale(kpis.csat_proxy, Math.round(((overallScore+1)/2)*100), 0, 100),
    nps_proxy: Math.round(clamp(typeof kpis.nps_proxy === 'number' ? kpis.nps_proxy : derivedNps, -100, 100)),
    sentiment_trend: oneOf(kpis.sentiment_trend, TREND, delta>0.1?'improving':delta<-0.1?'declining':'flat'),
    churn_risk: oneOf(kpis.churn_risk, RISK, 'medium'),
    escalation_risk: oneOf(kpis.escalation_risk, RISK, 'low'),
    resolution: oneOf(kpis.resolution, RES, 'partial'),
    empathy_score: normScale(kpis.empathy_score, 70, 0, 100),
    agent_compliance: normScale(kpis.agent_compliance, 70, 0, 100),
    emotion_intensity: normScale(kpis.emotion_intensity, derivedIntensity, 0, 100),
    silence_score: normScale(kpis.silence_score, derivedSilence, 0, 100),
    interruption_risk: oneOf(kpis.interruption_risk, RISK, derivedInterrupt),
    key_topics: Array.isArray(kpis.key_topics) ? kpis.key_topics.slice(0,6) : [],
    agent_sentiment: SENTIMENTS.includes(kpis.agent_sentiment) ? kpis.agent_sentiment : null,
    customer_sentiment: SENTIMENTS.includes(kpis.customer_sentiment) ? kpis.customer_sentiment : null,
    talk_listen_ratio: talkRatio,
    call_phase_sentiment: callPhase
  },
  meta: {
    sentence_count: merged.length,
    model: 'gpt-4o',
    source: 'n8n',
    processed_at: new Date().toISOString()
  }
};

return [{ json: result }];
